  351: {t:"\"وقت الإنارة\" في القانون هو:",a:["فترة الوقت من غروب الشمس وحتى شروقها فقط.","فترة الوقت من شروق الشمس وحتى غروبها.","الليل وكل وقت آخر تكون فيه الرؤية جيدة.","الليل وكل وقت آخر تكون فيه الرؤية مشوشة."],c:3},
  352: {t:"في أية مركبات يجب أن توجد مطفأة حريق؟",a:["في كل مركبة وزنها الإجمالي لغاية 3500كغم","في كل مركبة ميكانيكية ما عدا المركبة الخصوصية والتراكتور والدراجة النارية ذات العجلتين وذات الثلاث عجلات.","في التراكتور.","في كل مركبة  ركاب خصوصية."],c:1},
  353: {t:"هل يجب وضع سلال قمامة (سلال زبالة) في مركبة ركاب خصوصية؟",a:["نعم يجب وضع سلة قمامة (سلة زبالة) من النوع الذي صادقت عليه سلطة الترخيص.","كلا، يجب وضعها فقط في المركبة العمومية.","نعم ، يجب وضعها فقط في المركبة التجارية.","كلا ، لا يوجد واجب كهذا."],c:0},
  354: {t:"استعمال شاشات العرض (تلفزيون وما شابه ذلك) الظاهرة لعيني السائق، ما عدا شاشة عرض المراقبة والتوجيه في المركبة (G.P.S):",a:["مسموح لطمأنة السائق والركاب.","ممنوع ما دامت المركبة في حالة سير.","مسموح إذا كان السائق يضع نظارات واقية فقط.","ممنوع وحتى إذا كانت المركبة واقفة."],c:1},
