  379: {t:"حسب القانون، لأية مدة تبقى النقاط المسجلة بحق السائق؟",a:["لا توجد فترة محددة، ولا يوجد أي ذكر في الأنظمة بالنسبة لمدة تجميع النقاط.","فترة غير محددة، بموجب خطة النقاط الجديدة لا تُشطب النقاط على الإطلاق.","ست سنوات من تاريخ ارتكاب المخالفة عندما تتجمع بحق السائق 12 نقطة على الأقل.","سنتين من تاريخ ارتكاب المخالفة عندما تتجمع بحق السائق لغاية 20 نقطة."],c:3},
  380: {t:"أية إشارة من الإشارات التالية لا تسمح باستدارة إلى اليسار للسير بالاتجاه المعاكس (حذوة فرس إلى اليسار) ؟",a:["205","203","202","جميع الإشارات تمنع الاستدارة للسير في الاتجاه المعاكس (حذوة فرس)."],c:1},
  381: {t:"كيف تتصرف عندما ترى الإشارة؟",a:["عليك إعطاء حق الأولوية لحركة السير المقابلة في الطريق السريعة.","عليك الانتباه والسير على اليمين لأن حركة السير تصبح باتجاهين أمامك.","لك حق الأولوية بالنسبة لحركة السير المقابلة في الطريق.","ممنوع الرجوع إلى الخلف في مقطع الطريق الذي أمامك."],c:1},
