  383: {t:"أية إشارة تُنصب بالإضافة إلى الإشارة رقم: 216؟",a:["424","418","218","407"],c:2},
  384: {t:"ما هو الفرق بين الإشارتين؟",a:["الإشارة رقم: 135 تُحذر من الاقتراب من مكان عبور المشاة والإشارة رقم: 306 تدل على مكان عبور المشاة.","الإشارة رقم: 306 تُحذر من الاقتراب من مكان عبور المشاة والإشارة رقم: 135 تدل على مكان عبور المشاة.","لا يوجد فرق بينهما.","تُنصب الإشارة رقم: 135في طريق ليست بلدية بينما تُنصب الإشارة رقم: 306 في طريق داخل المدن."],c:0},
  385: {t:"ما معنى الاشارة ؟",a:["وصلت إلى مقطع فيه يجب على المركبة السريعة السير في المسلك الأيمن والمركبة البطيئة في المسلك الأيسر.","وصلت إلى مقطع فيه الوقوف مسموح على جانبي الشارع.","وصلت إلى مقطع فيه تغيير مؤقت للسرعة القصوى المسموح بها من 50كم/ساعة إلى 30كم/ساعة.","وصلت إلى نهاية مقطع السرعة الخاصة."],c:3},
  386: {t:"ما معنى الإشارة ؟",a:["ممنوع تجاوز باص.","نهاية مقطع الطريق التي يسري عليها منع التجاوز.","لا يجوز للشاحنات تجاوز مركبة ركاب خصوصية.","لا يجوز لمركبة ركاب خصوصية تجاوز شاحنة."],c:1},
  387: {t:"أية إشارة تأمر بإعطاء حق الأولوية لحركة السير حول الدوار؟",a:["121","303","307","301"],c:1},
  388: {t:"منطقة التروي (التمهل) في السير، هي منطقة:",a:["فيها السرعة القصوى المسموح بها 40كم/ساعة ومؤشرة بإشارة سير..","فيها السرعة القصوى المسموح بها 30كم/ساعة ومؤشرة بإشارة سير.","معدة لحركة سير المركبات البطيئة فقط.","فيها السرعة القصوى المسموح بها 25كم/ساعة ومؤشرة بإشارة سير.."],c:1},
  389: {t:"هل يُسمح بإيقاف مركبة بجانب حاجز لوقاية المارة؟",a:["مسموح لوقتٍ قصير فقط.","ممنوع إلا إذا وُجدت إشارة تدل على غير ذلك.","مسموح إذا لم يكن هناك عابري طريق من جهة حاجز الوقاية.","مسموح فقط من اجل إصعاد أو إنزال الركاب من المركبة."],c:1},
