  556: {t:"ما معنى الإشارة؟",a:["طريق للمركبات الميكانيكية فقط.","شارع إلى اليمين بدون مخرج.","مدخل خاص لمدارس أو رياض أطفال.","لك حق الأولوية في الطريق القاطعة."],c:1},
  557: {t:"إذا كان الشارع مقسماً بواسطة خط فاصل متقطع؟",a:["ممنوع أن تتجاوز حتى المكان الذي يُصبح فيه الخط متواصلاً.","مسموح أن تتجاوز مركبة بطيئة فقط.","ممنوع أن تتجاوز حتى المكان الذي نُصبت فيه الإشارة \"نهاية منع التجاوز\".","مسموح أن تتجاوز عندما تكون الطريق خالية."],c:3},
  558: {t:"ما معنى الإشارة؟",a:["مسموح لك السير في أي مسلك في الشارع.","لك حق الأولوية بالنسبة للمركبات المقتربة من الجهة المقابلة.","حركة سير باتجاهين أمامك","عدد المسالك في الشارع آخذ في الازدياد."],c:2},
  559: {t:"مسموح الاستدارة إلى اليسار للسير في الاتجاه المعاكس (حذوة فرس) :",a:["من كل مسلك في الشارع مؤشر بأسهم للاستدارة إلى اليسار أو إلى اليمين.","من مسلك الاستدارة إلى اليسار ومن كل مسلك آخر لا توجد فيه إشارة أو علامة تمنع مثل هذه الاستدارة.","من مسلك الاستدارة إلى اليسار فقط.","فقط من المسلك الأيسر الأقصى الذي يُسمح لك السير فيه."],c:1},
  560: {t:"من يُتوقع وصوله من الجهة المقابلة إذا كان السهم في الإشارة اصفر؟",a:["مركبة مستخدمة في المواصلات العمومية أو مركبة أخرى سمح لها بواسطة إشارة.","مركبة تنقل أكثر من راكبين.","باص سياحي فقط.","قطار فقط."],c:0},
  561: {t:"عندما ترى هذه الإشارة أمامك:",a:["أنت تدخل إلى مقطع فيه حركة السير من الجهة المقابلة مسموحة للمواصلات العمومية أو مركبة أخرى سمح لها بواسطة إشارة. .","مسموح للشاحنات السير بالاتجاه المعاكس.","أنت موجود في شارع باتجاه واحد، والشارع باتجاهين للمركبات التي لا يزيد وزنها عن 3500كغم.","أنت تدخل إلى شارع فيه مسلكان لكل اتجاه."],c:0},
  562: {t:"ما معنى الإشارة؟",a:["طريق للشاحنات فقط.","طريق للمركبات غير الميكانيكية فقط.","طريق للمركبات العمومية فقط.","طريق للمركبات الميكانيكية فقط."],c:3},
  563: {t:"هل يُسمح لدراجة هوائية بالدخول إلى طريق نُصبت على مدخلها الإشارة؟",a:["ممنوع.","مسموح في الطريق البلدية فقط.","مسموح دائماً.","مسموح في طريق ليست بلدية."],c:0},
