  639: {t:"أنت تسير باتجاه السهم، ما معنى الوسم (التأشير) على الشارع من يسارك؟",a:["خط حدود المساحة الفاصلة في طريق ليست بلدية.","سوف يؤشر عن قريب خط فاصل متواصل مزدوج...","شارع باتجاه واحد أمامك.","بداية طريق مشوشة أمامك."],c:1},
  640: {t:"ما معنى الوسم (التأشير) على سطح الطريق؟",a:["تجربة الدهان في الشارع.","مسموح الوقوف في الشارع في الجهة التي فيها الخط المتقطع.","سوف يبدأ عن قريب خط فاصل متواصل.","مسموح اختراق الخطوط فقط إذا كان الخط المتقطع موسوم( مرسوم) على يمين الخط  الفاصل المتواصل."],c:3},
  641: {t:"كيف يجب التصرف في المركبة عندما تظهر الإشارة على سطح الطريق؟",a:["مسموح للمركبة المؤشر عليها اختراق الخط الفاصل المتواصل.","يجب على المركبة المؤشر عليها السير في الجهة اليسرى للخط المتواصل.","ممنوع اختراق الخط الفاصل من قِبل السائق، غير أنه يُسمح له بالاستدارة إلى اليسار للسير بالاتجاه المعاكس (حذوة فرس).","يجب على سائق المركبة المؤشر عليها أن يسير على يمين الخطوط ويُمنع من اختراق الخط الفاصل المتواصل."],c:3},
  642: {t:"كيف يجب عليك التصرف عندما توجد عن يسارك الإشارة على سطح الطريق؟",a:["تمهل واعبر إلى الجهة اليسرى للشارع.","ممنوع اختراق الخط الفاصل المتواصل.","يجب السير دائماً في الجانب الأيمن من الخطوط.","مسموح اختراق الخطوط عندما يكون الخط المتقطع على الجهة اليمنى للخط المتواصل."],c:3},
  643: {t:"ما معنى الإشارة على سطح الطريق (خط اصفر)؟",a:["ممنوع السير بين الخطوط الصفراء.","خط  يدل على حدود حافة الشارع في المكان الذي لا توجد فيه أحجار حافة.","مسموح الوقوف في المنطقة التي على يسار الخط في - الطريق السريعة.","مسموح الوقوف في المنطقة التي على يمين الخط - في الطريق السريعة."],c:1},
  644: {t:"ما معنى الإشارة على سطح الطريق؟",a:["مسموح السير إلى الأمام فقط.","لك حق الأولوية في الطريق الضيقة بالنسبة لحركة السير القادمة من الاتجاه المعاكس.","تغيير الغاية من المسلك الأيسر.","ممنوع الاستدارة إلى اليسار من المسلك الأيسر."],c:2},
  645: {t:"كيف يجب الاستمرار بالسير حسب الوسم (التأشير)؟",a:["مسموح الاستدارة إلى اليسار من أي مسلك.","مسموح السير إلى الأمام أو إلى اليسار.","مسموح السير إلى اليمين فقط.","مسموح السير إلى اليسار فقط."],c:1},
