  1573: {t:"أنت تسير خلف مركبة بطيئة في الشارع وعن يسارك رُسم خط فاصل متواصل ابيض مزدوج:",a:["يُسمح لك بالتجاوز بشرط أن لا تعبر الخط الفاصل المتواصل المزدوج.","يُسمح لك بالتجاوز فقط إذا كانت المركبة البطيئة مركبة غير ميكانيكية.","يُسمح لك بالتجاوز وعبور الخط المتواصل المزدوج إذا كانت المركبة تسير ببطء لمدة طويلة.","يُسمح لك بالتجاوز حتى عن يسار الخط المتواصل المزدوج، إلا إذا كانت هناك إشارة خاصة تمنع ذلك."],c:0},
  1574: {t:"ما هي السرعة القصوى المسموح بها عند سياقة تراكتور حمولة في طريق ليست بلدية ؟",a:["حسب وضع الطريق والإشارات.","حسب تعليمات منتج التراكتور.","40كم/ساعة.","50كم/ساعة."],c:2},
  1578: {t:"أجهزة السيطرة على المركبة هي:",a:["الفرامل والمقود وأجهزة الصوت.","الفرامل والمقود وأجهزة التسارع.","المقود والتسارع وتكييف الهواء.","الفرامل والمقود وتكييف الهواء."],c:1},
  1580: {t:"قبل تعشيق الغيار من الغيار P إلى غيار آخر في صندوق الغيارات الأوتوماتيكي، على السائق:",a:["الضغط بقوة على دعسة الكلاتش.","الضغط بقوة على دعسة الوقود.","الضغط في آنٍ واحد على دعسة الفرامل وعلى دعسة الكلاتش وحينها يقوم بتعشيق الغيار المطلوب.","الضغط بقوة على دعسة الفرامل."],c:3},
  1582: {t:"درجة الرخصة المطلوبة لسياقة مركبة عمل تجر مجرورة وزنها الإجمالي أكثر من 3500كغم، هي؟",a:["B.","A.","C+E.","D."],c:2},
  1590: {t:"ما هي  أقل فتره زمنيه التي يجب أن يكون لدى السائق فيها رخصة سواقة من اجل أن يسمح له بسياقة  تراكتور وزنه أكثر من 3,200كغم أو إذا ألحقت به مجرورة وزنها الإجمالي أكثر من 4,000كغم؟",a:["سنتين من تاريخ حصوله على رخصة السياقة للتراكتور.","3 أشهر من تاريخ حصوله على رخصة السياقة للتراكتور.","6 أشهر من تاريخ حصوله على رخصة السياقة للتراكتور.","سنة من تاريخ حصوله على رخصة السياقة للتراكتور."],c:2},
