  1608: {t:"كيف تؤثر مصابيح المقدمة غير النظيفة على سائق المركبة في الليل؟",a:["مصابيح المقدمة غير النظيفة لا تؤثر على الإطلاق على السائق أثناء السياقة.","تضر بمدى الرؤية لديه.","تسبب في بهر النظر الذاتي للسائق.","تزيد من مدى الرؤية لديه."],c:1},
  1622: {t:"بموجب القانون ، المساحة المضاءة من مصابيح مقدمة المركبة في الليل وفي جو صافي، يجب أن تكون:",a:["بالضوء العالي – على الأقل 120م، وبالضوء الواطئ – على الأقل 50م..","بالضوء العالي – على الأقل 100م، وبالضوء الواطئ – على الأقل 30م.","مسافة أضواء المقدمة لم تُحدد في القانون وإنما هي حسب تقدير منتج المركبة.","بالضوء العالي – على الأقل 150م، وبالضوء الواطئ – على الأقل 60م.."],c:1},
  1625: {t:"هل المجرورة الزراعية ملزمة بمثلث تحذير؟",a:["فقط المجرورة ذات وزن إجمالي لغاية 4000كغم.","كلا.","نعم.","فقط المجرورة الصغيرة ذات وزن إجمالي لغاية 500كغم."],c:2},
  1628: {t:"هل يجوز لسائق التراكتور عبور (قطع) الرصيف؟",a:["نعم، من اجل أخذ راكب.","نعم، من اجل الدخول إلى ساحة أو كراج.","نعم، من اجل تجاوز عائق في الطريق.","نعم، من اجل إنزال راكب."],c:1},
  1636: {t:"على سائق مركبة تجارية وزنها الإجمالي المسموح به أكثر من 6000كغم، أن يستريح 25 ساعة متواصلة، خارج العمل، كل فترة:",a:["10 أيام على الأكثر.","6 أيام على الأكثر.","8 أيام على الأكثر.","12 يوم على الأكثر."],c:2},
